import { cva } from 'class-variance-authority'
import { brutalHoverLift } from '@/lib/brutal-interaction-variants'
import { CLOSE_BUTTON_BASE_CLASSES, baseModalContentClasses } from '@/lib/modal-variants'
import { centeredModalAnimationClasses } from '@/lib/floating-animation-classes'

export const dialogContentVariants = cva(
    [
        'fixed left-[50%] top-[50%] z-50 translate-x-[-50%] translate-y-[-50%]',
        'w-full p-6',
        ...baseModalContentClasses,
        'text-brutal-fg',
        ...centeredModalAnimationClasses,
    ],
    {
        variants: {
            size: {
                sm: 'max-w-sm',
                default: 'max-w-lg',
                lg: 'max-w-2xl',
                xl: 'max-w-4xl',
                full: 'max-w-[calc(100vw-2rem)]',
            },
        },
        defaultVariants: {
            size: 'default',
        },
    }
)

export const dialogCloseVariants = cva(
    [
        ...CLOSE_BUTTON_BASE_CLASSES,
        'absolute right-4 top-4',
        brutalHoverLift,
    ]
)

/* eslint-disable vue/one-component-per-file */
import { createVNode, render, ref, h, defineComponent, watch, computed } from 'vue'
import type { Component, VNode } from 'vue'
import { DialogRoot } from 'reka-ui'
import DialogEnhanced from '@/components/ui/dialog/DialogEnhanced.vue'
import DialogHeader from '@/components/ui/dialog/DialogHeader.vue'
import DialogTitle from '@/components/ui/dialog/DialogTitle.vue'
import DialogDescription from '@/components/ui/dialog/DialogDescription.vue'
import DialogFooter from '@/components/ui/dialog/DialogFooter.vue'
import Button from '@/components/ui/button/Button.vue'
import Input from '@/components/ui/input/Input.vue'
import { useLocale } from '@/composables/useLocale'

export type RenderableContent = string | Component | VNode | (() => string | Component | VNode | null)

export interface ShowDialogOptions {
    title?: string
    content?: RenderableContent
    footer?: RenderableContent
    draggable?: boolean
    dragHandle?: string | HTMLElement
    bounds?: 'parent' | 'viewport' | { top: number; left: number; right: number; bottom: number }
    initialPosition?: { x: number; y: number }
    resizable?: boolean
    minWidth?: number
    minHeight?: number
    maxWidth?: number
    maxHeight?: number
    aspectRatio?: number
    showCloseButton?: boolean
    forceMount?: boolean
    fullscreen?: boolean
    beforeClose?: ((done: () => void) => void) | (() => boolean | Promise<boolean>)
    destroyOnClose?: boolean
    zIndex?: number
    class?: string
}

export interface MessageBoxOptions extends ShowDialogOptions {
    message?: string
    type?: 'info' | 'success' | 'warning' | 'error'
    showCancelButton?: boolean
    cancelButtonText?: string
    confirmButtonText?: string
    confirmButtonClass?: string
    cancelButtonClass?: string
    showInput?: boolean
    inputPlaceholder?: string
    inputValue?: string
    inputPattern?: RegExp
    inputErrorMessage?: string
}

function getDialogEnhancedProps(options: ShowDialogOptions): Record<string, unknown> {
    const keys: Array<keyof ShowDialogOptions> = [
        'draggable',
        'dragHandle',
        'bounds',
        'initialPosition',
        'resizable',
        'minWidth',
        'minHeight',
        'maxWidth',
        'maxHeight',
        'aspectRatio',
        'showCloseButton',
        'forceMount',
        'fullscreen',
        'beforeClose',
        'destroyOnClose',
        'zIndex',
        'class'
    ]
    const props: Record<string, unknown> = {}
    for (const key of keys) {
        if (options[key] !== undefined) {
            props[key] = options[key]
        }
    }
    return props
}

export function showDialog(options: ShowDialogOptions = {}) {
    const container = document.createElement('div')
    document.body.appendChild(container)

    const isOpen = ref(true)

    let resolvePromise: () => void
    const promise = new Promise<void>((resolve) => {
        resolvePromise = () => resolve()
    })

    const close = () => {
        isOpen.value = false
    }

    const destroy = () => {
        render(null, container)
        container.remove()
        resolvePromise()
    }

    watch(isOpen, (newVal) => {
        if (!newVal) {
            setTimeout(destroy, 300)
        }
    })

    const renderSlot = (slotVal: RenderableContent | undefined) => {
        if (!slotVal) return null
        if (typeof slotVal === 'string') {
            return h('div', { class: 'text-sm font-medium leading-relaxed' }, slotVal)
        }
        if (typeof slotVal === 'function') {
            return (slotVal as () => VNode)()
        }
        return h(slotVal as Component)
    }

    const component = defineComponent({
        setup() {
            return () => {
                return h(DialogRoot, {
                    open: isOpen.value,
                    'onUpdate:open': (val: boolean) => {
                        isOpen.value = val
                    }
                }, {
                    default: () => h(DialogEnhanced, {
                        ...getDialogEnhancedProps(options),
                        'onUpdate:open': (val: boolean) => {
                            isOpen.value = val
                        }
                    }, {
                        default: () => [
                            options.title ? h(DialogHeader, null, {
                                default: () => h(DialogTitle, null, { default: () => options.title })
                            }) : null,
                            options.content ? h('div', { class: 'py-4' }, [renderSlot(options.content)]) : null,
                            options.footer ? h(DialogFooter, null, {
                                default: () => renderSlot(options.footer)
                            }) : null
                        ]
                    })
                })
            }
        }
    })

    const vnode = createVNode(component)
    render(vnode, container)

    return {
        close,
        promise
    }
}

export function showMessageBox(options: MessageBoxOptions = {}) {
    const container = document.createElement('div')
    document.body.appendChild(container)

    const isOpen = ref(true)
    const inputValue = ref(options.inputValue || '')
    const hasValidationError = ref(false)
    const errorMessage = ref(options.inputErrorMessage || '输入格式不正确')

    let resolvePromise: (value: { value: string } | undefined) => void
    let rejectPromise: (reason?: unknown) => void

    const promise = new Promise<{ value: string } | undefined>((resolve, reject) => {
        resolvePromise = resolve
        rejectPromise = reject
    })

    const close = () => {
        isOpen.value = false
    }

    const destroy = () => {
        render(null, container)
        container.remove()
    }

    watch(isOpen, (newVal) => {
        if (!newVal) {
            setTimeout(destroy, 300)
        }
    })

    const handleConfirm = () => {
        if (options.showInput) {
            if (options.inputPattern && !options.inputPattern.test(inputValue.value)) {
                hasValidationError.value = true
                return
            }
            resolvePromise({ value: inputValue.value })
        } else {
            resolvePromise(undefined)
        }
        close()
    }

    const handleCancel = () => {
        rejectPromise('cancel')
        close()
    }

    const component = defineComponent({
        setup() {
            const { locale } = useLocale()
            const isZh = computed(() => {
                return locale.value.dialog.close === '关闭'
            })

            const defaultConfirmText = computed(() => isZh.value ? '确定' : 'Confirm')
            const defaultCancelText = computed(() => isZh.value ? '取消' : 'Cancel')

            return () => {
                return h(DialogRoot, {
                    open: isOpen.value,
                    'onUpdate:open': (val: boolean) => {
                        isOpen.value = val
                        if (!val) {
                            rejectPromise('close')
                        }
                    }
                }, {
                    default: () => h(DialogEnhanced, {
                        ...getDialogEnhancedProps(options),
                        'onUpdate:open': (val: boolean) => {
                            isOpen.value = val
                            if (!val) {
                                rejectPromise('close')
                            }
                        }
                    }, {
                        default: () => [
                            options.title ? h(DialogHeader, null, {
                                default: () => h(DialogTitle, null, { default: () => options.title })
                            }) : null,

                            h('div', { class: 'py-4 flex flex-col gap-4' }, [
                                options.message ? h(DialogDescription, null, { default: () => options.message }) : null,

                                options.showInput ? h(Input, {
                                    modelValue: inputValue.value,
                                    'onUpdate:modelValue': (val: string) => {
                                        inputValue.value = val
                                        hasValidationError.value = false
                                    },
                                    placeholder: options.inputPlaceholder,
                                    variant: hasValidationError.value ? 'error' : 'default',
                                    errorMessage: hasValidationError.value ? errorMessage.value : undefined
                                }) : null
                            ]),

                            h(DialogFooter, { class: 'flex justify-end gap-3 mt-4' }, {
                                default: () => [
                                    options.showCancelButton ? h(Button, {
                                        variant: 'outline',
                                        class: options.cancelButtonClass,
                                        onClick: handleCancel
                                    }, {
                                        default: () => options.cancelButtonText || defaultCancelText.value
                                    }) : null,
                                    h(Button, {
                                        variant: 'default',
                                        class: options.confirmButtonClass,
                                        onClick: handleConfirm
                                    }, {
                                        default: () => options.confirmButtonText || defaultConfirmText.value
                                    })
                                ]
                            })
                        ]
                    })
                })
            }
        }
    })

    const vnode = createVNode(component)
    render(vnode, container)

    return {
        close,
        promise
    }
}

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

import { ref, computed, watch, onMounted, onBeforeUnmount, toValue, type Ref, type ComputedRef, type CSSProperties, type MaybeRefOrGetter } from 'vue'
import { hasDocument } from '@/lib/env'
import { DIALOG_MIN_WIDTH_PX, DIALOG_MIN_HEIGHT_PX } from '@/lib/defaults'
import type { ResizeCorner } from '@/types'
export type { ResizeCorner }

export interface DraggableDialogOptions {
    draggable?: boolean
    dragHandle?: string | HTMLElement
    bounds?: 'parent' | 'viewport' | { top: number; left: number; right: number; bottom: number }
    initialPosition?: { x: number; y: number }
}

export interface ResizableDialogOptions {
    resizable?: boolean
    minWidth?: number
    minHeight?: number
    maxWidth?: number
    maxHeight?: number
    aspectRatio?: number
}

export interface UseDialogEnhancedOptions extends DraggableDialogOptions, ResizableDialogOptions {
    beforeClose?: ((done: () => void) => void) | (() => boolean | Promise<boolean>)
    onOpen?: () => void
    onClose?: () => void
    onUpdateOpen?: (value: boolean) => void
}

export interface UseDialogEnhancedReturn {
    contentRef: Ref<HTMLElement | null>
    isDragging: Ref<boolean>
    isResizing: Ref<boolean>
    position: Ref<{ x: number; y: number }>
    size: Ref<{ width: number; height: number }>
    contentStyle: Ref<CSSProperties>
    onDragStart: (e: MouseEvent) => void
    onResizeStart: (e: MouseEvent, corner: ResizeCorner) => void
    handleClose: () => Promise<void>
    initPosition: () => void
    initSize: () => void
}

/** Interactive HTML tags that should not trigger drag */
const INTERACTIVE_TAGS = ['INPUT', 'TEXTAREA', 'SELECT', 'BUTTON', 'A']

export function isInteractiveElement(target: HTMLElement): boolean {
    return INTERACTIVE_TAGS.includes(target.tagName) || target.isContentEditable
}

export function useDialogEnhanced(
    options?: MaybeRefOrGetter<UseDialogEnhancedOptions>,
): UseDialogEnhancedReturn {
    // Reactive source: accepts either a plain object (static options) or a
    // getter function (reactive options that re-evaluate when tracked deps
    // change — typically `() => ({ draggable: props.draggable, ... })`).
    const optionsRef: ComputedRef<UseDialogEnhancedOptions> = computed(() => toValue(options) ?? {})

    // Getter proxy: every access reads the latest options object, so
    // closures (event handlers, watchers) always see up-to-date values.
    const opt = {
        get draggable() { return optionsRef.value.draggable ?? false },
        get dragHandle() { return optionsRef.value.dragHandle },
        get bounds() { return optionsRef.value.bounds ?? 'viewport' },
        get initialPosition() { return optionsRef.value.initialPosition },
        get resizable() { return optionsRef.value.resizable ?? false },
        get minWidth() { return optionsRef.value.minWidth ?? DIALOG_MIN_WIDTH_PX },
        get minHeight() { return optionsRef.value.minHeight ?? DIALOG_MIN_HEIGHT_PX },
        get maxWidth() { return optionsRef.value.maxWidth },
        get maxHeight() { return optionsRef.value.maxHeight },
        get aspectRatio() { return optionsRef.value.aspectRatio },
        get beforeClose() { return optionsRef.value.beforeClose },
        get onOpen() { return optionsRef.value.onOpen },
        get onClose() { return optionsRef.value.onClose },
        get onUpdateOpen() { return optionsRef.value.onUpdateOpen },
    }

    const contentRef = ref<HTMLElement | null>(null)
    const isDragging = ref(false)
    const isResizing = ref(false)
    const position = ref({ x: 0, y: 0 })
    const size = ref({ width: 0, height: 0 })
    const dragStart = ref({ x: 0, y: 0 })
    const resizeStart = ref({ x: 0, y: 0, width: 0, height: 0, corner: 'se' })

    // ── Content Style ──────────────────────────────────────────────

    const contentStyle = computed<CSSProperties>(() => {
        const style: CSSProperties = {}

        if (opt.draggable) {
            style.transform = `translate(calc(-50% + ${position.value.x}px), calc(-50% + ${position.value.y}px))`
            style.position = 'fixed'
            style.top = '50%'
            style.left = '50%'
            style.margin = '0'
        }

        if (opt.resizable && size.value.width > 0 && size.value.height > 0) {
            style.width = `${size.value.width}px`
            style.height = `${size.value.height}px`
        }

        return style
    })

    // ── Drag Handle Resolution ─────────────────────────────────────

    function getDragHandle(): HTMLElement | null {
        if (!opt.draggable) return null
        if (typeof opt.dragHandle === 'string') {
            return contentRef.value?.querySelector(opt.dragHandle) ?? null
        }
        if (opt.dragHandle instanceof HTMLElement) {
            return opt.dragHandle
        }
        return contentRef.value
    }

    // ── Position Constraints ───────────────────────────────────────

    function constrainPosition(newX: number, newY: number): { x: number; y: number } {
        const rect = contentRef.value?.getBoundingClientRect()
        if (!rect) return { x: newX, y: newY }

        if (opt.bounds === 'viewport') {
            return {
                x: Math.max(-rect.width / 2, Math.min(newX, window.innerWidth - rect.width / 2)),
                y: Math.max(-rect.height / 2, Math.min(newY, window.innerHeight - rect.height / 2)),
            }
        } else if (opt.bounds === 'parent') {
            const parentRect = contentRef.value?.parentElement?.getBoundingClientRect()
            if (parentRect) {
                return {
                    x: Math.max(parentRect.left - rect.width / 2, Math.min(newX, parentRect.right - rect.width / 2)),
                    y: Math.max(parentRect.top - rect.height / 2, Math.min(newY, parentRect.bottom - rect.height / 2)),
                }
            }
        } else if (typeof opt.bounds === 'object') {
            return {
                x: Math.max(opt.bounds.left - rect.width / 2, Math.min(newX, opt.bounds.right - rect.width / 2)),
                y: Math.max(opt.bounds.top - rect.height / 2, Math.min(newY, opt.bounds.bottom - rect.height / 2)),
            }
        }

        return { x: newX, y: newY }
    }

    // ── Drag Handlers ──────────────────────────────────────────────

    function onDragStart(e: MouseEvent) {
        if (!hasDocument) return
        if (!opt.draggable) return

        const target = e.target
        if (!(target instanceof HTMLElement) || isInteractiveElement(target)) return

        const handle = getDragHandle()
        if (handle && !handle.contains(target)) return

        isDragging.value = true
        dragStart.value = {
            x: e.clientX - position.value.x,
            y: e.clientY - position.value.y,
        }

        document.addEventListener('mousemove', onDragMove)
        document.addEventListener('mouseup', onDragEnd)
        e.preventDefault()
    }

    function onDragMove(e: MouseEvent) {
        if (!isDragging.value) return

        const newX = e.clientX - dragStart.value.x
        const newY = e.clientY - dragStart.value.y
        const constrained = constrainPosition(newX, newY)
        position.value = constrained
    }

    function onDragEnd() {
        if (!hasDocument) return
        isDragging.value = false
        document.removeEventListener('mousemove', onDragMove)
        document.removeEventListener('mouseup', onDragEnd)
    }

    // ── Resize Handlers ────────────────────────────────────────────

    function onResizeStart(e: MouseEvent, corner: ResizeCorner) {
        if (!hasDocument) return
        if (!opt.resizable) return

        isResizing.value = true
        resizeStart.value = {
            x: e.clientX,
            y: e.clientY,
            width: size.value.width,
            height: size.value.height,
            corner,
        }

        document.addEventListener('mousemove', onResizeMove)
        document.addEventListener('mouseup', onResizeEnd)
        e.preventDefault()
        e.stopPropagation()
    }

    function onResizeMove(e: MouseEvent) {
        if (!isResizing.value) return

        const deltaX = e.clientX - resizeStart.value.x
        const deltaY = e.clientY - resizeStart.value.y

        let newWidth = resizeStart.value.width
        let newHeight = resizeStart.value.height

        switch (resizeStart.value.corner) {
            case 'se':
                newWidth += deltaX
                newHeight += deltaY
                break
            case 'sw':
                newWidth -= deltaX
                newHeight += deltaY
                break
            case 'ne':
                newWidth += deltaX
                newHeight -= deltaY
                break
            case 'nw':
                newWidth -= deltaX
                newHeight -= deltaY
                break
        }

        if (opt.minWidth) newWidth = Math.max(opt.minWidth, newWidth)
        if (opt.minHeight) newHeight = Math.max(opt.minHeight, newHeight)
        if (opt.maxWidth) newWidth = Math.min(opt.maxWidth, newWidth)
        if (opt.maxHeight) newHeight = Math.min(opt.maxHeight, newHeight)

        if (opt.aspectRatio) {
            newHeight = newWidth / opt.aspectRatio
            if (opt.minHeight) newHeight = Math.max(opt.minHeight, newHeight)
            if (opt.maxHeight) newHeight = Math.min(opt.maxHeight, newHeight)
        }

        size.value = { width: newWidth, height: newHeight }
    }

    function onResizeEnd() {
        if (!hasDocument) return
        isResizing.value = false
        document.removeEventListener('mousemove', onResizeMove)
        document.removeEventListener('mouseup', onResizeEnd)
    }

    // ── Close Handling ─────────────────────────────────────────────

    function performClose(): void {
        opt.onClose?.()
        opt.onUpdateOpen?.(false)
    }

    async function handleClose(): Promise<void> {
        if (!opt.beforeClose) {
            performClose()
            return
        }

        // Detect mode: callback mode (parameter length > 0) or Promise mode
        if (opt.beforeClose.length > 0) {
            // Callback mode
            (opt.beforeClose as (done: () => void) => void)(() => {
                performClose()
            })
        } else {
            // Promise mode
            const result = await (opt.beforeClose as () => boolean | Promise<boolean>)()
            if (result !== false) {
                performClose()
            }
        }
    }

    // ── Initialization ─────────────────────────────────────────────

    function initPosition(): void {
        if (opt.initialPosition) {
            position.value = { ...opt.initialPosition }
        } else {
            position.value = { x: 0, y: 0 }
        }
    }

    let sizeRafId: number | null = null

    function initSize(): void {
        if (contentRef.value) {
            sizeRafId = requestAnimationFrame(() => {
                const rect = contentRef.value?.getBoundingClientRect()
                if (rect && rect.width > 0 && rect.height > 0) {
                    size.value = { width: rect.width, height: rect.height }
                }
            })
        }
    }

    // ── Watchers & Lifecycle ───────────────────────────────────────

    // Reactive watcher: fires whenever optionsRef yields a new initialPosition
    // (works when the caller passes a getter that reads reactive props).
    watch(() => opt.initialPosition, (newPos) => {
        if (newPos) {
            position.value = { ...newPos }
        }
    })

    onMounted(() => {
        initPosition()
        initSize()
        opt.onOpen?.()
    })

    onBeforeUnmount(() => {
        if (sizeRafId !== null) {
            cancelAnimationFrame(sizeRafId)
        }
        if (!hasDocument) return
        document.removeEventListener('mousemove', onDragMove)
        document.removeEventListener('mouseup', onDragEnd)
        document.removeEventListener('mousemove', onResizeMove)
        document.removeEventListener('mouseup', onResizeEnd)
    })

    return {
        contentRef,
        isDragging,
        isResizing,
        position,
        size,
        contentStyle,
        onDragStart,
        onResizeStart,
        handleClose,
        initPosition,
        initSize,
    }
}

import { cva, type VariantProps } from 'class-variance-authority'

export const iconSizeVariants = cva('', {
    variants: {
        size: {
            xs: 'h-2.5 w-2.5',
            sm: 'h-3 w-3',
            default: 'h-4 w-4',
            lg: 'h-5 w-5',
            xl: 'h-6 w-6',
            '2xl': 'h-8 w-8',
        },
    },
    defaultVariants: { size: 'default' },
})

export type IconSize = NonNullable<VariantProps<typeof iconSizeVariants>['size']>

/**
 * Shared default values for component configuration.
 */

/** Default autoplay interval in milliseconds (used by Carousel, GlitchText, GlitchButton) */
export const DEFAULT_AUTOPLAY_INTERVAL_MS = 3000

// ── Color Picker ──────────────────────────────────────────────

/** Precision multiplier for HSV saturation/value rounding (→ 0.1% steps) */
export const HSV_PERCENT_PRECISION = 1000

/** Maximum hue angle in degrees */
export const HUE_DEGREES = 360

/** Maximum saturation / value percentage */
export const HSV_COMPONENT_MAX = 100

/** Precision multiplier for alpha rounding (→ 0.01 steps) */
export const ALPHA_PRECISION = 100

// ── Dialog ────────────────────────────────────────────────────

